const body = $input.first().json.body || $input.first().json;
const items = body.items || [];
if (!items.length) throw new Error('No items to embed');
return [{json: {items, source_type: body.source_type || 'unknown'}}];

const items = $('Prepare Chunks').first().json.items;
const source_type = $('Prepare Chunks').first().json.source_type;
const embeddings = $input.first().json.data || [];
const results = [];
for (let i = 0; i < embeddings.length; i++) {
  const item = items[i] || {};
  const vec = '[' + embeddings[i].embedding.join(',') + ']';
  const text = ((item.title || '') + ' ' + (item.text || '')).substring(0, 10000);
  const meta = JSON.stringify(item.metadata || {});
  results.push({
    json: {
      source_type,
      source_id: item.id || '',
      source_title: item.title || '',
      chunk_text: text,
      chunk_index: item.chunk_index || 0,
      metadata: meta,
      embedding: vec
    }
  });
}
return results;
